UPDATE universities SET description = 'Doğuş University (or simply Doğuş) is a foundation university located in Ümraniye, Istanbul.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/e/eb/Dogus_universitesi_yeni_logo.png/500px-Dogus_universitesi_yeni_logo.png', website_url = 'https://en.wikipedia.org/wiki/Do%C4%9Fu%C5%9F_University' WHERE id = 'bcd47e58-4301-4891-b464-8bb15f724ef2';
UPDATE universities SET description = 'Altınbaş University is a foundation university in Istanbul, Turkey. The university was established in 2008 as Istanbul Kemerburgaz University and changed to its current name in 2017. Altınbaş University has more than 5000 international students from 89 countries, approximately 40% of the students are international. The university has 3 campuses located in Istanbul, which are in Bağcılar, Bakırköy and Şişli. Home to 9 undergraduate schools, 3 graduate schools, 2 vocational schools as of the academic year 2019–2020, Altınbaş University is currently offering 30 bachelor''s degree programmes, 34 associate degree programmes, 28 master''s degree programmes and 6 PhD programmes.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/7a/Antinbas_Uni_logo.png/120px-Antinbas_Uni_logo.png', website_url = 'https://en.wikipedia.org/wiki/Alt%C4%B1nba%C5%9F_University' WHERE id = '444b65a7-f0f9-4039-8b97-5513d974c604';
UPDATE universities SET description = 'İstinye University is a private university in Istanbul, established in 2015 by the 21st Century Anatolian Foundation. It builds upon the MLP Care Group, which integrates the hospital brands “Liv Hospital,” “Medical Park,” and “VM Medical Park.”
The university operates two campuses, the Topkapı Campus and the Vadi Istanbul Campus, and utilizes İstinye University Hospital Medical Park Gaziosmanpaşa and İstinye University Hospital Liv Hospital Bahçeşehir as affiliated training hospitals. İSÜ Liv Hospital Bahçeşehir hosts multidisciplinary departments under one roof, including the organ transplantation center, stroke center, medical oncology, hand surgery, reconstructive surgery, IVF Center, interventional radiology and advanced interventional radiology. The hospital is also among the few facilities with both a pediatric intensive care unit and a closed-system intensive care unit.', cover_image_url = NULL, website_url = 'https://en.wikipedia.org/wiki/%C4%B0stinye_University' WHERE id = '147f61e2-ebe9-4363-b9a5-54c7c4652ae7';
UPDATE universities SET description = 'Abdullah Gül (  GOOL, Turkish: [abduɫˈɫah ˈɟyl]; born 29 October 1950) is a Turkish politician who served as the president of Turkey from 2007 to 2014. He previously served for four months as Prime Minister from 2002 to 2003, and concurrently served as both Deputy Prime Minister and as Foreign Minister between 2003 and 2007. He is currently a member of the Advisory Panel for the President of the Islamic Development Bank.
Advocating staunch Islamist political views during his university years, Gül became a Member of Parliament for Kayseri in 1991 and was re-elected in 1995, 1999, 2002, and 2007. Initially a member of the Islamist Welfare Party, Gül joined the Virtue Party in 1998 after the former was banned for anti-secular activities. When the party split into hardline Islamist and modernist factions in 2000, Gül joined fellow party member Recep Tayyip Erdoğan in advocating the need for reform and moderation. He ran against serving leader Recai Kutan for the Virtue Party leadership at a time when Erdoğan was banned from holding political office. As the candidate for the modernist camp, he came second with 521 votes while Kutan won 633. He co-founded the moderate Justice and Development Party (AKP) with Erdoğan in 2001 after the Virtue Party was shut down in the same year, while hardline conservative members founded the Felicity Party instead.
Gül became prime minister after the AKP won a landslide victory in the 2002 general election while Erdoğan was still banned from office. His government removed Erdoğan''s political ban by March 2003, after which Erdoğan became an MP for Siirt in a by-election and took over as prime minister. Gül subsequently served as Minister of Foreign Affairs and Deputy Prime Minister until 2007. His subsequent bid for the Presidency drew strong and highly vocal opposition from ardent supporters of secularism in Turkey and was initially blocked by the Constitutional Court due to concerns over his Islamist political background. He was eventually elected Turkey''s first president with a background in Islamic politics after the 2007 snap general election.
As president, Gül came under criticism for giving assent to controversial laws which have been regarded by the political opposition as unconstitutional. In June 2013, he signed a bill restricting alcohol consumption into law despite initially indicating a possible veto, which was seen as a contributing factor to sparking the Gezi Park protests. Other controversies included a law tightening internet regulation in 2013, a law increasing political control over the judiciary in 2014 designed to protect then Prime Minister Erdoğan and others from corruption charges and a law giving the National Intelligence Organization (MİT) controversial new powers also in 2014. Gül took a mediating approach during the Gezi Park anti-government protests and government corruption scandals.

', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f1/%D0%90%D0%B1%D0%B4%D1%83%D0%BB%D0%BB%D0%B0%D1%85_%D0%93%D1%8E%D0%BB%D1%8C_%288613568906%29.jpg/500px-%D0%90%D0%B1%D0%B4%D1%83%D0%BB%D0%BB%D0%B0%D1%85_%D0%93%D1%8E%D0%BB%D1%8C_%288613568906%29.jpg', website_url = 'https://en.wikipedia.org/wiki/Abdullah_G%C3%BCl' WHERE id = 'b8e8d2e0-c66b-4c8c-96ad-40ab0094e34a';
UPDATE universities SET description = 'Haliç University (Turkish: Haliç Üniversitesi) is a university in Turkey, which was founded in 1998 by the Children Leukemia Foundation.
Haliç University offers 21 academic departments, with three schools: the School of Nursing, the School of Physical Education and Sport, and the School of Health Sciences and Conservatory.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/4c/Hali%C3%A7_University_logo_%282022%29.svg/960px-Hali%C3%A7_University_logo_%282022%29.svg.png', website_url = 'https://en.wikipedia.org/wiki/Hali%C3%A7_University' WHERE id = '15450bdc-7937-41b4-8084-b78bffe9e5b0';
UPDATE universities SET description = 'Istanbul Arel University (Turkish: İstanbul Arel Üniversitesi) is a private nonprofit university located in Istanbul, Turkey. It was established in 2007 by the Kemal Gözükara Education and Culture Foundation. Teaching is done mostly in English, and there are bachelor, masters and doctoral programmes.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/e/ef/%C4%B0stanbul_Arel_University_logo.svg/960px-%C4%B0stanbul_Arel_University_logo.svg.png', website_url = 'https://en.wikipedia.org/wiki/Istanbul_Arel_University' WHERE id = '800a845e-4b53-4f28-a61a-863792db1a59';
UPDATE universities SET description = 'Malaysia–Turkey relations are the foreign relations between Malaysia and Turkey. Turkey has an embassy in Kuala Lumpur, and Malaysia has an embassy in Ankara and consulate-general in Istanbul. Both countries are full members of the World Trade Organization (WTO) and the Organisation of the Islamic Conference (OIC). Both countries are also classified as regional powers and middle powers in their respective regions.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/86/Malaysia_Turkey_Locator.svg/960px-Malaysia_Turkey_Locator.svg.png', website_url = 'https://en.wikipedia.org/wiki/Malaysia%E2%80%93Turkey_relations' WHERE id = '9286640a-b095-4c7a-8c41-ec85f7f95c20';
UPDATE universities SET description = 'Istanbul University (Turkish: İstanbul Üniversitesi), also known as University of Istanbul, is a public research university located in Istanbul, Turkey. Founded by Mehmed II on May 30, 1453, a day after the conquest of Constantinople by the Turks, it was reformed as the first Ottoman higher education institution influenced by European approaches. The successor institution, which has been operating under its current name since 1933, is the first university in modern Turkey. 
The university has 58,809 undergraduate, graduate, and doctoral students studying in 112 academic units, including faculties, institutes, colleges, and vocational schools at 9 campuses. The main campus is adjacent to Beyazıt Square in Fatih, the capital district of the province, on the European side of the city.
Istanbul University alumni include Nobel Prize in Chemistry winner Aziz Sancar and Nobel Prize in Literature winner Orhan Pamuk, as well as President of Turkey Abdullah Gül, six Prime Ministers of Turkey, Grand Mufti for Bosnia and Herzegovina Mehmed Džemaludin Čaušević, including Suat Hayri Ürgüplü, Sadi Irmak, Nihat Erim, Refik Saydam, Naim Talu, and Yıldırım Akbulut. The alumni also include the longest-serving President of Israel Yitzhak Ben-Zvi, as well as David Ben-Gurion and Moshe Sharett, who both served as Prime Ministers of Israel.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/1/1e/%C4%B0stanbul_%C3%9Cniversitesi_Logo.svg/960px-%C4%B0stanbul_%C3%9Cniversitesi_Logo.svg.png', website_url = 'https://en.wikipedia.org/wiki/Istanbul_University' WHERE id = '54b72d4e-0ae2-4e7a-97b0-4e80f9eea309';
UPDATE universities SET description = 'Istanbul University (Turkish: İstanbul Üniversitesi), also known as University of Istanbul, is a public research university located in Istanbul, Turkey. Founded by Mehmed II on May 30, 1453, a day after the conquest of Constantinople by the Turks, it was reformed as the first Ottoman higher education institution influenced by European approaches. The successor institution, which has been operating under its current name since 1933, is the first university in modern Turkey. 
The university has 58,809 undergraduate, graduate, and doctoral students studying in 112 academic units, including faculties, institutes, colleges, and vocational schools at 9 campuses. The main campus is adjacent to Beyazıt Square in Fatih, the capital district of the province, on the European side of the city.
Istanbul University alumni include Nobel Prize in Chemistry winner Aziz Sancar and Nobel Prize in Literature winner Orhan Pamuk, as well as President of Turkey Abdullah Gül, six Prime Ministers of Turkey, Grand Mufti for Bosnia and Herzegovina Mehmed Džemaludin Čaušević, including Suat Hayri Ürgüplü, Sadi Irmak, Nihat Erim, Refik Saydam, Naim Talu, and Yıldırım Akbulut. The alumni also include the longest-serving President of Israel Yitzhak Ben-Zvi, as well as David Ben-Gurion and Moshe Sharett, who both served as Prime Ministers of Israel.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/1/1e/%C4%B0stanbul_%C3%9Cniversitesi_Logo.svg/960px-%C4%B0stanbul_%C3%9Cniversitesi_Logo.svg.png', website_url = 'https://en.wikipedia.org/wiki/Istanbul_University' WHERE id = '9ce0218e-9dad-40a0-9d53-f809751dd14b';
UPDATE universities SET description = 'Piri Reis (Turkish: Pîrî Reis; born Muhiddin Piri; c. 1470–1553) was an Ottoman Turkish cartographer, admiral, navigator, and corsair. He is best known for his 1513 world map and his nautical atlas, the Kitab-ı Bahriye (Book of the Sea). His maps combined classical sources, his own seafaring knowledge, and information from new European discoveries. His cartography was more engaged with the Age of Discovery than other Ottoman works from the period.
Piri Reis began his maritime career sailing with his uncle, the corsair Kemal Reis, with whom he entered Ottoman naval service. He later commanded his own ship in the Ottoman–Venetian wars and, following his uncle’s death, began the cartographic work for which he became best known. In 1516, he took part in the conquest of Egypt, and presented his world maps and atlases as gifts to the Ottoman Sultans. Later, as grand admiral of the Ottoman fleet in the Indian Ocean, Piri Reis led successful campaigns in the Red Sea, but was executed following his retreat from the siege of Hormuz Island at the mouth of the Persian Gulf.
During his lifetime, Piri Reis'' cartography received little appreciation, but many copies of the Kitab-ı Bahriye were produced after his death. The 1929 rediscovery of his first world map, during renovations to the Topkapı Palace in Istanbul, increased interest in his work in part because it cites many contemporary Portuguese explorers and a now-lost map by Christopher Columbus. The rediscovery made his career a point of national pride for Turkey. Although the map has been the subject of fringe theories based on the disproven hypothesis that the map depicted an ice-free Antarctica, studies have shown no significant similarities between the map and Antarctica''s subglacial coast. Nevertheless, this speculation has increased interest in Piri Reis'' cartography.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/7f/Piri_reis.jpg/330px-Piri_reis.jpg', website_url = 'https://en.wikipedia.org/wiki/Piri_Reis' WHERE id = '13535e9a-f999-42e3-aa29-5c295bd4aaaa';
UPDATE universities SET description = 'Bahçeşehir Cyprus University (Turkish: Bahçeşehir Kıbrıs Üniversitesi) is a private university established in 2017 in the city of Nicosia, Turkish Republic of Northern Cyprus.', cover_image_url = NULL, website_url = 'https://en.wikipedia.org/wiki/Bah%C3%A7e%C5%9Fehir_Cyprus_University' WHERE id = 'd9d78288-e1ec-481d-b3bb-dfdb8ede71eb';
UPDATE universities SET description = 'Cyprus International University (CIU; Turkish: Uluslararası Kıbrıs Üniversitesi) is an English-language private university in Northern Cyprus. It is located in the capital, North Nicosia and was established in 1997.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/c/cd/Uluslararas%C4%B1_K%C4%B1br%C4%B1s_%C3%9Cniversitesi_Resmi_Logo.png/500px-Uluslararas%C4%B1_K%C4%B1br%C4%B1s_%C3%9Cniversitesi_Resmi_Logo.png', website_url = 'https://en.wikipedia.org/wiki/Cyprus_International_University' WHERE id = 'b82cd605-77fe-4098-b095-116f0af2ec52';
UPDATE universities SET description = 'The International Islamic University Malaysia (IIUM) is a public university in Malaysia. Headquartered in Gombak, Selangor, IIUM has six other campuses all over Malaysia: two medical-centric campuses and a Centre for Foundation Studies in Gambang, Pahang, two city campuses in Kuala Lumpur, and a language and tourism campus in Pagoh, Johor.
The university is sponsored by eight governments and the Organisation of the Islamic Cooperation (OIC). It is distinct from the Indonesian International Islamic University and International Islamic University Chittagong, Bangladesh.
The university was established on 23 May 1983 and founded upon Islamic principles.  Islamic values are inculcated into all disciplines. IIUM offers bachelor''s, master''s and doctoral degrees courses at its 14 faculties or "Kulliyyah" ("Kulliyyat", in plural).
Since 1987, IIUM has produced more than 70,000 graduates and undergraduates from more than 100 countries, as of 2020. Most of them were from Malaysia. Its medium of instruction is English, with Arabic used in courses related to the study of Islamic Sciences, although the university also uses Bahasa Malaysia in certain courses.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/d/df/International_Islamic_University_of_Malaysia_building.jpg/960px-International_Islamic_University_of_Malaysia_building.jpg', website_url = 'https://en.wikipedia.org/wiki/International_Islamic_University_Malaysia' WHERE id = '48fb43c8-4b20-4cbf-b444-69246c7aec65';
UPDATE universities SET description = 'Istanbul is the largest city in Turkey, constituting the country''s economic, cultural, and historical center. With a population of over 15 million, it is home to 18% of the population of Turkey. Istanbul is among the largest cities in Europe and in the world by population. It is a city on two continents; about two-thirds of its population live in Europe and the rest in Asia. Istanbul straddles the Bosphorus – one of the world''s busiest waterways – in northwestern Turkey, between the Sea of Marmara and the Black Sea. Its area of 5,461 square kilometers (2,109 mi2) is coterminous with Istanbul Province.
The city now known as Istanbul developed to become one of the most significant cities in history. Byzantium was founded on the Sarayburnu promontory by Greek colonists, potentially in the seventh century BC. Over nearly 16 centuries following its reestablishment as Constantinople in 330 AD, it served as the capital of three empires: the Roman Empire (later known as the Byzantine Empire, 330–1204 and 1261–1453), the Latin Empire (1204–1261), and the Ottoman Empire (1453–1922). It was instrumental in the advancement of Christianity during Roman and Byzantine times, before the Ottomans conquered the city in 1453 and transformed it into an Islamic stronghold and the seat of the last caliphate. Although the Republic of Turkey established its capital in Ankara, palaces and imperial mosques still line Istanbul''s hills as visible reminders of the city''s previous central role. The historic centre of Istanbul is a UNESCO World Heritage Site 
Istanbul''s strategic position along the historic Silk Road, rail networks to Europe and West Asia, and the only sea route between the Black Sea and the Mediterranean have helped foster an eclectic populace, although less so since the establishment of the Republic in 1923. Overlooked for the new capital during the interwar period, the city has since regained much of its prominence. The population of the city has increased tenfold since the 1950s, as migrants from across Anatolia have flocked to the metropolis and city limits have expanded to accommodate them. The majority of Istanbul’s Turkish citizens are of ethnic Turkish origin, whereas ethnic Kurds represent the largest ethnic minority in the city. By the late twentieth century, a number of arts festivals had been established, and sustained infrastructure development led to the emergence of an extensive and multifaceted transportation network 
Considered an alpha global city, Istanbul accounts for about thirty percent of Turkey''s economy. The Istanbul-İzmit area is one of the main industrial regions in Turkey. In 2024, Euromonitor International ranked Istanbul as the second most visited city in the world. Istanbul is home to two international airports, multiple ports, and numerous universities. It is among the top 100 science and technology clusters in the world. The city hosts a large part of Turkish football and sports in general, with clubs such as Galatasaray, Fenerbahçe and Beşiktaş. Istanbul is vulnerable to earthquakes as it is in close proximity to the North Anatolian Fault.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/c/cb/Historical_peninsula_and_modern_skyline_of_Istanbul.jpg/960px-Historical_peninsula_and_modern_skyline_of_Istanbul.jpg', website_url = 'https://en.wikipedia.org/wiki/Istanbul' WHERE id = '79fa117f-430b-4c7b-9f74-7d7d7d6aa104';
UPDATE universities SET description = 'Poznań (Polish: [ˈpɔznaj̃] or [ˈpɔznaɲ] ) is a city on the River Warta in west Poland, within the Greater Poland region. The city is an important cultural and business center and one of Poland''s most populous regions with many regional customs such as Saint John''s Fair (Jarmark Świętojański), traditional Saint Martin''s croissants and a local dialect. Among its most important heritage sites are the Renaissance Old Town, Town Hall and Poznań Cathedral.
Poznań is the fifth-largest  city in Poland. As of 2023, the city''s population is 540,146, while the Poznań metropolitan area (Metropolia Poznań) comprising Poznań County and several other communities is inhabited by over 1.029 million people. It is one of four historical capitals of medieval Poland and the ancient capital of the Greater Poland region, currently the administrative capital of the province called Greater Poland Voivodeship.
Poznań is a center of trade, sports, education, technology and tourism. It is an important academic site, with about 130,000 students and Adam Mickiewicz University, the third largest Polish university. The city serves as the seat of the oldest Polish diocese, now being one of the most populous Catholic archdioceses in the country. The city also hosts the Poznań International Fair, the biggest industrial fair in Poland and one of the largest in Europe. The city''s other renowned landmarks include the National Museum, Grand Theatre, Fara Church and the Imperial Castle.
Poznań is classified as a Gamma−global city by Globalization and World Cities Research Network. According to several rankings it is one of the most business-friendly cities in Poland. It also ranks highly in safety and healthcare quality. The city of Poznań has also, many times, won the prize awarded by "Superbrands" for a very high quality city brand. In 2012, the Poznań''s Art and Business Centre "Stary Browar" won a competition organised by National Geographic Traveler and was given the first prize as one of the seven "New Polish Wonders". Companies headquartered in the city include energy provider Enea, e-commerce company Allegro and convenience store chain Żabka.
The official patron saints of Poznań are Saint Peter and Paul of Tarsus, the patrons of the cathedral. Martin of Tours – the patron of the main street Święty Marcin – is also regarded as one of the patron saints of the city.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/d/d9/Stary_Rynek_w_Poznaniu%2C_widok_z_drona_%28cropped%29.jpg/960px-Stary_Rynek_w_Poznaniu%2C_widok_z_drona_%28cropped%29.jpg', website_url = 'https://en.wikipedia.org/wiki/Pozna%C5%84' WHERE id = '38507134-1547-4d56-9b39-36cf53924364';
UPDATE universities SET description = 'The Air Cargo Challenge is an aeronautical engineering student competition that is held in Europe every two years.
This competition was held for the first time in 2003 and it was founded by a group of Aerospace students in Lisbon. The competition is primarily directed to aeronautical and aerospace engineering students, similarly to the north-American Design/Build/Fly.
The main objective is to design and build a radio-controlled aircraft that is able to fly with the highest possible payload according with the rules established in the competition regulations, which vary in each edition.
The team''s score is not only given by the performance demonstrated in the flight competition part, but also by the technical quality of the project, through the evaluation of the design report and drawings.
The event''s first edition (ACC''03) was organized by the APAE: Associação Portuguesa de Aeronáutica e Espaço (Portuguese Association of Aeronautics and Space), an aerospace group from Instituto Superior Técnico. From the ACC''07 onwards, the competition grew to an international level under the umbrella of EUROAVIA, the European Association of Aerospace Students, and the winning team got the possibility of organizing the next edition. The ACC of 2011 was held in the University of Stuttgart, August 2011, organized by the AKAModell Stuttgart together with the EUROAVIA Stuttgart. The Universidade da Beira Interior was the winner of this edition, thus it took place in Portugal''. Again, the Team from Stuttgart won this Edition, and got the organization responsibility. In 2017 the 2015 winner HUSZ organized the event in Zagreb. The competition took place in Stuttgart again on August 12–17, 2019. After a one-year delay due to the Covid pandemic, the competition was held in Munich in the summer of 2022. The 2022 winner ADDI organized the 2024 edition on 10–12 July in Aachen, Germany. The next ACC 2026 will be held in Stuttgart, Germany.', cover_image_url = NULL, website_url = 'https://en.wikipedia.org/wiki/Air_Cargo_Challenge' WHERE id = 'fd11cfdc-d9d3-4cff-a562-c9bc862489c3';
UPDATE universities SET description = 'Nil Köksal is a Turkish-born Canadian radio and television journalist, serving as primary host of As It Happens on CBC Radio One. Previously, she was the weekday anchor of the radio network''s World Report. 
Köksal has worked for the Canadian Broadcasting Corporation since 2001, and has been a member of the CBC News: Morning team since November 2005. She graduated from the University of British Columbia with a bachelor''s degree and from Ryerson University with a Bachelor of Applied Arts in journalism. She was born in Istanbul, Turkey and raised in both Ontario and Vancouver.
In 2013, she won the Canadian Screen Award for Best Local Breaking News Reportage at the 1st Canadian Screen Awards, for her coverage of the death of Mariam Makhniashvili.', cover_image_url = NULL, website_url = 'https://en.wikipedia.org/wiki/Nil_K%C3%B6ksal' WHERE id = 'f5336e59-a965-43c9-8761-1a12293355f0';
UPDATE universities SET description = 'A maritime museum (sometimes nautical museum) is a museum specializing in the display of objects relating to ships and travel on large bodies of water. A subcategory of maritime museums are naval museums, which focus on navies and the military use of the sea.
The great prize of a maritime museum is a historic ship (or a replica) made accessible as a museum ship, but as these are large and require a considerable budget to maintain, many museums preserve smaller or more fragile ships or partial ships within the museum buildings. Most museums exhibit interesting pieces of ships (such as a figurehead or cannon), ship models, and miscellaneous small items associated with ships and shipping, like cutlery, uniforms, and so forth.
Ship modellers often have a close association with maritime museums; not only does the museum have items that help the modeller achieve better accuracy, but the museum provides a display space for models larger than will comfortably fit in a modeller''s home, and of the museum is happy to take a ship model as a donation. Museums will also commission models.
There are thousands of maritime museums in the world. Many belong to the International Congress of Maritime Museums, which coordinates members'' efforts to acquire, preserve, and display their material. There is a risk that too many maritime museums might dilute the experience for the public, while a poorly managed museum might put other municipalities off from the idea of hosting such a museum.
At 80 acres (32 ha) the Chatham Historic Dockyard in Kent, UK can lay claim to being the largest maritime museum in the world, incorporating numerous dockyard buildings, including a 1/4 mile long ropewalk, spinning rooms, covered slips, dry docks, smithery, sail loft, rigging house, mould loft, church, as well as three historic warships, it is the best preserved dockyard from the Age of Sail. However, the UK''s National Maritime Museum in Greenwich is also a contender, with many items of great historical significance, such as the actual uniform worn by Horatio Nelson at the Battle of Trafalgar. The largest in the United States of America is 19 acres (7.7 ha), Mystic Seaport in Mystic, Connecticut; it preserves not only a number of sailing ships, but also many original seaport buildings, including a ship chandlery, sail loft, ropewalk, and so forth. 
A recent activity of maritime museums is to build replicas of ships, since there are few survivors that have not already been restored and put on display. Another is operating a museum harbour, most notably in Germany and the Netherlands but elsewhere too, that offers mooring to privately owned historical vessels, which can be watched but not boarded.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/82/Wisconsin_museum.JPG/500px-Wisconsin_museum.JPG', website_url = 'https://en.wikipedia.org/wiki/Maritime_museum' WHERE id = 'ee87d964-49af-4f6a-846c-7f4b77f526bb';
UPDATE universities SET description = 'Warsaw, officially the Capital City of Warsaw, is the capital and largest city of Poland. The metropolis stands on the River Vistula in east-central Poland. Its population is officially estimated at 1.86 million residents within a greater metropolitan area of 3.27 million residents, which makes Warsaw the 6th most-populous city in the European Union. The city area measures 517 square kilometres (200 square miles) and comprises 18 districts, while the metropolitan area covers 6,100 square kilometres (2,355 square miles). Warsaw is classified as an alpha global city, a major political, economic and cultural hub, and the country''s seat of government. It is also the capital of the Masovian Voivodeship.
Warsaw traces its origins to a small fishing town in Masovia. The city rose to prominence in the late 16th century, when Sigismund III decided to move the Polish capital and his royal court from Kraków. Warsaw surpassed Gdańsk as Poland''s most populous city by the 18th century. It served as the capital of the Polish–Lithuanian Commonwealth until 1795, and subsequently as the seat of Napoleon''s Duchy of Warsaw. The 19th century and its Industrial Revolution brought a demographic boom, which made it one of the largest and most densely populated cities in Europe. Known then for its elegant architecture and boulevards, Warsaw was bombed and besieged at the start of World War II in 1939. Much of the historic city was destroyed and its diverse population decimated by the Ghetto Uprising in 1943, the general Warsaw Uprising in 1944, and systematic razing.
Warsaw is served by three international airports, the busiest being Warsaw Chopin, as well as Warsaw Modlin and Warsaw Radom Airport. Major public transport services operating in the city include the Warsaw Metro, buses, commuter rail service and an extensive tram network. The city is a significant economic centre for the region, with the Warsaw Stock Exchange being the largest in Central and Eastern Europe. It is the base for Frontex, the European Union agency for external border security, and ODIHR, one of the principal institutions of the Organization for Security and Co-operation in Europe. Warsaw has one of Europe''s highest concentrations of skyscrapers, and the Varso Tower is the tallest building in the European Union.
The city''s primary educational and cultural institutions comprise the University of Warsaw, the Warsaw University of Technology, the SGH Warsaw School of Economics, the Chopin University of Music, the Polish Academy of Sciences, the National Philharmonic Orchestra, the National Museum, and the Warsaw Grand Theatre, which is among the largest in Europe. The reconstructed Old Town, which represents a variety of European architectural styles, was listed as a World Heritage Site by UNESCO in 1980. Other landmarks include the Royal Castle, Sigismund''s Column, the Wilanów Palace, the Palace on the Isle, St. John''s Archcathedral, Main Market Square, and numerous churches and mansions along the Royal Route. Warsaw is a green capital, with around a quarter of the city''s area occupied by parks. In sports, the city is home to Legia and Polonia sports clubs and hosts the annual Warsaw Marathon.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/35/Aleja_Niepdleglosci_Warsaw_2022_aerial_%28cropped%29.jpg/960px-Aleja_Niepdleglosci_Warsaw_2022_aerial_%28cropped%29.jpg', website_url = 'https://en.wikipedia.org/wiki/Warsaw' WHERE id = '9c0efe1c-d6ad-47d9-86c7-8c681f0a47a8';
UPDATE universities SET description = 'Brunel University of London (BUL) is a public research university located in the Uxbridge area of London, England. It is named after Isambard Kingdom Brunel, a Victorian engineer and pioneer of the Industrial Revolution. It became a university in June 1966, when Brunel College of Advanced Technology was awarded a royal charter and became Brunel University; it is sometimes considered a plate glass university.
In 2014 the university formally adopted the name Brunel University London, and in 2024 became the University of London''s 17th member, adopting the trading name Brunel University of London. Since 2014 the university has been organised into three colleges: the College of Business, Arts and Social Sciences; the College of Engineering, Design and Physical Sciences; and the College of Health, Medicine and Life Sciences.
Brunel has more than 16,000 students and 2,200 staff, and an annual income of £271.3 million (2021–22), of which £22.4 million was from research grants and contracts, with an expenditure of £311.9 million. The university won the Queen''s Anniversary Prize in 2011. BUL is a member of the Association of Commonwealth Universities, the European University Association, and Universities UK.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/85/Brunel-logo.png/500px-Brunel-logo.png', website_url = 'https://en.wikipedia.org/wiki/Brunel_University_of_London' WHERE id = 'f8c197cd-d238-4bd6-bb1a-71baa74be6e0';
UPDATE universities SET description = 'Leeds Bradford Airport (IATA: LBA, ICAO: EGNM) is located in Yeadon, in the City of Leeds Metropolitan District in West Yorkshire, England, about 7 miles (11 km) northwest of Leeds city centre, and about 9 miles (14 km) northeast from Bradford city centre. It serves Leeds and Bradford and the wider Yorkshire region including York, Wakefield and Harrogate, and is the largest airport in Yorkshire. The airport was in public ownership until May 2007, when it was bought by Bridgepoint Capital for £145.5 million. Bridgepoint sold it in 2017 to AMP Capital. In December 2025, Spanish national airport company AENA acquired a majority stake in the airport.
Leeds Bradford opened on 17 October 1931 when it was known as Leeds and Bradford Municipal Aerodrome or Yeadon Aerodrome; some locals still refer to it as Yeadon Airport. Largely used for general aviation and training purposes early on, the first scheduled flights commenced on 8 April 1935. To accommodate passenger traffic, work commenced on the first terminal in the late 1930s, although only the first wing was completed before the Second World War.
British aircraft manufacturer Avro constructed a shadow factory called the Leeds Bradford Airport Depot to the north of the airport, which was the largest free-standing structure in Europe at that time. Avro produced around 5,515 aircraft before it closed in December 1946 and civil flights recommenced the following year. It is located where Leeds Bradford Airport Industrial Estate is today.
In 1965, a new runway opened. After Yeadon''s terminal was destroyed in a fire, a replacement was completed in 1968. In the early 1980s, runway extensions were completed that enabled it to be classified as a regional airport. On 4 November 1984, the day a runway extension was opened, Wardair commenced transatlantic flights to Toronto, using Boeing 747s. On 2 August 1986, an Air France Concorde charter flight from Paris landed for the first time, drawing an estimated crowd of 70,000 people. More Concorde charter flights took place until 2000. In 1994, the airport''s operational hour restrictions were removed, enabling flights at any time of day. Since 1996, the terminal has been expanded in the terms of size and facilities. In 2007, nearly 2.9 million passengers passed through the airport, an 88% increase in seven years and more than twice as many compared with 1997 (1.2 million).
Leeds Bradford has a CAA Public Use Aerodrome Licence (Number P800) that allows flights for passenger transport and flight training. The airport operates scheduled flights to many European destinations and a limited number of domestic destinations. It is the highest airport in England at an elevation of 681 ft (208 m). By the number of passengers handled in 2024, Leeds Bradford was the 13th busiest airport in the UK. It is a base for Jet2.com, which has its headquarters at the airport.

', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/67/LBIA_terminal_1.jpg/960px-LBIA_terminal_1.jpg', website_url = 'https://en.wikipedia.org/wiki/Leeds_Bradford_Airport' WHERE id = 'cf68a013-9239-4e28-8ece-7772bab09100';
UPDATE universities SET description = 'Cardiff is the capital and largest city of Wales. Cardiff had a population of 383,919 in 2024 and forms a principal area officially known as the City and County of Cardiff (Welsh: Dinas a Sir Caerdydd). The city is the eleventh largest in the United Kingdom. Located in the southeast of Wales and in the Cardiff Capital Region, Cardiff is the county town of the historic county of Glamorgan and in 1974–1996 of South Glamorgan. It belongs to the Eurocities network of the largest European cities. A small town until the early 19th century, its prominence as a port for coal when mining began in the region helped its expansion. In 1905, it was ranked as a city and in 1955 proclaimed capital of Wales. The Cardiff urban area covers a larger area outside the county boundary, including the towns of Dinas Powys and Penarth.
Cardiff is the main commercial centre of Wales as well as the base for the Senedd, the Welsh Parliament. At the 2021 census, the unitary authority area population was put at 362,400. The population of the wider urban area in 2011 was 479,000. In 2011, it ranked sixth in the world in a National Geographic magazine list of alternative tourist destinations. It is the most popular destination in Wales with 21.3 million visitors in 2017. It was voted as the best city in the UK at the 2023 Readers'' Choice Awards.  
Cardiff is a major centre for television and film production (such as the 2005 revival of Doctor Who, Torchwood and Sherlock) and is the Welsh base for the main national broadcasters.
Cardiff Bay contains the Senedd building and the Wales Millennium Centre arts complex. Work continues at Cardiff Bay and in the centre on projects such as Cardiff International Sports Village, BBC drama village, and a new business district.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/1/1f/Cardiff_Bay_WMC.jpg', website_url = 'https://en.wikipedia.org/wiki/Cardiff' WHERE id = '409cb001-1b8f-48ed-8ffc-4446e3fa237f';
UPDATE universities SET description = 'Istanbul Medipol University (Turkish: İstanbul Medipol Üniversitesi) is a private university in Istanbul, Turkey. The university was established in 2009 by the Turkey Education, Health, and Research Foundation, emphasizes medical education and health sciences. The foundation was established by Fahrettin Koca, who served as the Minister of Health in the 67th government of Turkey.
The university comprises 12 faculties, five institutes, and four vocational schools. As of 2025, the university has a total enrollment of 49,757 students, including 33,216 undergraduates, 1,037 graduate students, and 14,722 associate degree students. The academic staff consists of 1,538 faculty members, supported by 2,572 administrative personnel. The university offers 74 undergraduate programs across 12 faculties, with 24 of these programs conducted in English.', cover_image_url = NULL, website_url = 'https://en.wikipedia.org/wiki/Istanbul_Medipol_University' WHERE id = '112845ef-4e23-42ba-9f9d-72314f8a09c2';
UPDATE universities SET description = 'Istanbul Ticaret University (Turkish: İstanbul Ticaret Üniversitesi) is a foundation university which was founded in 2001 by the Istanbul Chamber of Commerce Education and Social Services Foundation.
Istanbul Ticaret University, which provides education and training in two different campuses in Istanbul is a city university which is located in the most central points of Istanbul with six faculties, 24 departments, four institutes and 65 postgraduate programs.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/44/%C4%B0stanbul_Ticaret_%C3%9Cniversitesi_Logo.png/960px-%C4%B0stanbul_Ticaret_%C3%9Cniversitesi_Logo.png', website_url = 'https://en.wikipedia.org/wiki/Istanbul_Commerce_University' WHERE id = '5434d64d-3bd0-49dc-9fdf-0b3ec61ccdae';
UPDATE universities SET description = 'KTO Karatay University is a private (non-profit foundation) university in Konya, Turkey. It was established in 2009 by the Konya Chamber of Commerce Education and Health Foundation. The institution traces its historical roots to the Karatay Madrasa, founded in 1251 during the Seljuk period. 
As of the 2025–2026 academic year, the university comprised five faculties, three schools, three vocational schools, and a graduate institute, with an approximate enrollment of 10,000 students.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/49/KtoLOGO.png/960px-KtoLOGO.png', website_url = 'https://en.wikipedia.org/wiki/KTO_Karatay_University' WHERE id = '3c1ab842-5541-45c0-afa1-6760c26f6488';
UPDATE universities SET description = 'Kyrenia is a city on the northern coast of Cyprus, noted for its historic harbour and castle. It is under the control of Northern Cyprus.
While there is evidence showing that the wider region of Kyrenia has been populated before, Greek myths suggest Kyrenia was founded by the Achaeans Cepheus and Praxandrus who ended up there after the Trojan War. The heroes named the new city after their hometown Kyrenia in Achaea, Greece.
As the town grew prosperous, the Romans established the foundations of its castle in the 1st century AD. Kyrenia grew in importance after the 9th century due to the safety offered by the castle, and played a pivotal role under Lusignan rule as the city never capitulated. The castle was most recently modified by the Venetians in the 15th century. The city surrendered to the Ottoman Empire in 1571.
The city''s population was almost equally divided between Muslims and Christians in 1831, with a slight Muslim majority. However, with the advent of British rule, many Turkish Cypriots fled to Anatolia, and the town came to be predominantly inhabited by Greek Cypriots. While the city suffered little intercommunal violence, its Greek Cypriot inhabitants, numbering around 2,650, fled or were forcefully displaced in the wake of the Turkish invasion in 1974. Currently, the city is populated by Turkish Cypriots, mainland Turkish settlers, and British expats, with a municipal population of 33,207.
Kyrenia is a cultural and economical centre, described as the tourism capital of Northern Cyprus. It is home to numerous hotels, nightlife and a port. It hosts an annual culture and arts festival with hundreds of participating artists and performers and is home to three universities with a student population around 14,000.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/c/c4/Kyrenia_01-2017_img04_view_from_castle_bastion.jpg/960px-Kyrenia_01-2017_img04_view_from_castle_bastion.jpg', website_url = 'https://en.wikipedia.org/wiki/Kyrenia' WHERE id = '8fc5278d-1b3c-46ae-ba33-83f569883ee5';
UPDATE universities SET description = 'The International Islamic University Malaysia (IIUM) is a public university in Malaysia. Headquartered in Gombak, Selangor, IIUM has six other campuses all over Malaysia: two medical-centric campuses and a Centre for Foundation Studies in Gambang, Pahang, two city campuses in Kuala Lumpur, and a language and tourism campus in Pagoh, Johor.
The university is sponsored by eight governments and the Organisation of the Islamic Cooperation (OIC). It is distinct from the Indonesian International Islamic University and International Islamic University Chittagong, Bangladesh.
The university was established on 23 May 1983 and founded upon Islamic principles.  Islamic values are inculcated into all disciplines. IIUM offers bachelor''s, master''s and doctoral degrees courses at its 14 faculties or "Kulliyyah" ("Kulliyyat", in plural).
Since 1987, IIUM has produced more than 70,000 graduates and undergraduates from more than 100 countries, as of 2020. Most of them were from Malaysia. Its medium of instruction is English, with Arabic used in courses related to the study of Islamic Sciences, although the university also uses Bahasa Malaysia in certain courses.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/d/df/International_Islamic_University_of_Malaysia_building.jpg/960px-International_Islamic_University_of_Malaysia_building.jpg', website_url = 'https://en.wikipedia.org/wiki/International_Islamic_University_Malaysia' WHERE id = '6128d064-6504-41d9-9bd9-3b54d112d5c8';
UPDATE universities SET description = 'This is a list of pro-Palestinian protests on university campuses in 2024 since protests escalated on April 17, beginning with the Columbia University campus occupation. As of May 6, student protests have occurred in 45 out of 50 states in the United States, and the District of Columbia, with encampments, occupations, walkouts or sit-ins on almost 140 campuses.
Encampments were established at 36 institutions in the United Kingdom, including 21 of the 24 institutions in the Russell Group, with some institutions having more than one encampment; across universities in Australia, beginning with the University of Sydney; and in Canada, including an encampment at McGill University. On May 7, protests spread further on European campuses after mass arrests at the University of Amsterdam campus occupation, including occupation of campus buildings at Leipzig University in Germany, Sciences Po in France, and Ghent University in Belgium. As of May 8, protests have taken place in more than 25 countries. On May 13, approximately 1,000 Dutch students and university staff took part in a national walk-out.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/7a/Demonstrators_Reinforcing_a_Barricade.jpg/960px-Demonstrators_Reinforcing_a_Barricade.jpg', website_url = 'https://en.wikipedia.org/wiki/List_of_pro-Palestinian_protests_on_university_campuses_in_2024' WHERE id = 'f7fdb45c-5079-4f08-a03e-2fb8839336bf';
UPDATE universities SET description = 'Bournemouth (  BORN-məth) is a coastal resort town in the Bournemouth, Christchurch and Poole unitary authority area, in the ceremonial county of Dorset, on the south coast of England. At the 2021 census, the built-up area had a population of 196,455, making it the largest town in Dorset.
Previously an uninhabited heathland, visited only by fishermen and occasional smugglers, a health resort was founded in the area by Lewis Tregonwell in 1810. After the Ringwood, Christchurch and Bournemouth Railway opened in 1870, Bournemouth grew into an important resort town, which today attracts over five million visitors annually for its coastline and nightlife.
The town is a population centre within the South East Dorset conurbation and is known for its seven-mile stretch of golden sand, with well-known spots including Alum Chine Beach, Durley Chine Beach, and Bournemouth Central Beach. The shoreline continues westward and gradually merges into the affluent Sandbanks area and Poole. Alongside tourism, financial services now play a significant role in the local economy.
The town centre is notable for its Victorian architecture. St Peter''s Church features a 202-foot (62 m) spire and is one of three Grade I listed churches in the borough. The town has an events venue and a concert hall, the Bournemouth International Centre (BIC) and Pavilion Theatre respectively. Bournemouth is also home to the Premier League football club, AFC Bournemouth, and to Bournemouth University, which has a growing reputation in fields such as media, business and health.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/b/b4/Bournemouth_-_Seafront_-_geograph.org.uk_-_838983.jpg/500px-Bournemouth_-_Seafront_-_geograph.org.uk_-_838983.jpg', website_url = 'https://en.wikipedia.org/wiki/Bournemouth' WHERE id = '6f113ac2-46e8-4c11-ab13-94e1a67f9f20';
UPDATE universities SET description = 'The Stadium of Light is an all-seater football stadium in Sunderland, England, and the eighth and current home to Premier League club Sunderland. With seating for 49,000 spectators, the Stadium of Light is the 10th largest football stadium in England. The stadium primarily hosts Sunderland home matches. The stadium was named by chairman Bob Murray to reflect the coal mining heritage of the North East and the former Monkwearmouth Colliery site on which it stands. A Davy lamp monument stands at the entrance to reflect the coal mining industry that brought prosperity to the town.
As well as hosting Sunderland games, the stadium has hosted three matches for the England national football team, as well as an England under-20, an England under-21 and two England women''s team matches. With an original capacity of 42,000, it was expanded in 2000 to seat 49,000. Its simple design is apparently to allow for redevelopments up to a capacity of 64,000. The attendance record at the Stadium of Light is 48,353 set on 13 April 2002, when Sunderland played Liverpool with the visitors running out 1–0 winners. Along with hosting football matches, the stadium has played host to performers such as Beyoncé, Rihanna, Oasis, Take That, Kings of Leon, P!nk, Coldplay, Spice Girls and Elton John. The ground also holds conference and banqueting suites, the Black Cats Bar, and a club shop selling Sunderland merchandise.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/b/b1/Sunderland_stadium_of_light.jpg/960px-Sunderland_stadium_of_light.jpg', website_url = 'https://en.wikipedia.org/wiki/Stadium_of_Light' WHERE id = '9b59fa3f-d1e5-401e-b128-245134b87603';
UPDATE universities SET description = 'Near East University (NEU; Turkish: Yakın Doğu Üniversitesi, commonly referred to as YDÜ) is a private university located in Northern Cyprus. It was founded in North Nicosia in 1988, by Suat Günsel, a Turkish Cypriot who is the 100% owner of NEU. The chairman of the board of trustees is his son, Irfan Günsel.
The Near East University currently has 16 faculties with 98 departments, 4 vocational schools, 2 high schools and 4 graduate schools offering programs at undergraduate and postgraduate levels.
With over 25,000 students, it is the largest university in Northern Cyprus.', cover_image_url = NULL, website_url = 'https://en.wikipedia.org/wiki/Near_East_University' WHERE id = 'ac680009-3f83-4693-bfad-9552e93563e2';
UPDATE universities SET description = 'Bahçeşehir University or commonly abbreviated as BAU is a private university located around the Bosphorus in Çırağan Caddesi, Beşiktaş, Istanbul. The Grand National Assembly of Turkey authorized the establishment of Bahçeşehir University by the Bahçeşehir Uğur Education Foundation in 1998. In February 1998, an academic and strategic collaboration was signed with San Diego State University in California.  The university''s first cohort of students enrolled following the first university placement exam in the 1999–2000 academic year. The current rector is Prof. Dr. Şirin Karadeniz.
Bahçeşehir University is a member of BAU Global, the international education network of Bahçeşehir Uğur Educational Institutions (Turkish: Bahçeşehir Uğur Eğitim Kurumları). BAU Global includes nine universities, four language schools, and two K-12 schools, Bahçeşehir College and Uğur Schools (Turkish: Uğur Okulları). Bahçeşehir University has established a long-term collaboration with Harvard University, focusing on various academic and research initiatives.
Bahçeşehir University consists of 8 faculties, 1 school of languages, and 2 vocational schools. Four institutes offer post-graduate education. The university has a total of 17,048 registered students, including 10,137 undergraduate students, 4,716 graduate students, and 1,072 associate degree students. The academic staff includes 1,047 faculty members, and 506 administrative personnel are employed by the university. The university operates across 4 campuses in Istanbul. The Bahçeşehir University Library, covering an area of 1,400 square meters, offers a collection of 250,000 publications, including books and e-books. Additionally, the campus hosts five cafés and restaurants, and the conference hall has a total audience capacity of 1,000.
Bahçeşehir University was awarded the "Superbrands of Turkey" title in 2007.', cover_image_url = NULL, website_url = 'https://en.wikipedia.org/wiki/Bah%C3%A7e%C5%9Fehir_University' WHERE id = '127c30f5-bb0c-4b3d-b691-2b35cb1e944e';
UPDATE universities SET description = 'Warsaw, officially the Capital City of Warsaw, is the capital and largest city of Poland. The metropolis stands on the River Vistula in east-central Poland. Its population is officially estimated at 1.86 million residents within a greater metropolitan area of 3.27 million residents, which makes Warsaw the 6th most-populous city in the European Union. The city area measures 517 square kilometres (200 square miles) and comprises 18 districts, while the metropolitan area covers 6,100 square kilometres (2,355 square miles). Warsaw is classified as an alpha global city, a major political, economic and cultural hub, and the country''s seat of government. It is also the capital of the Masovian Voivodeship.
Warsaw traces its origins to a small fishing town in Masovia. The city rose to prominence in the late 16th century, when Sigismund III decided to move the Polish capital and his royal court from Kraków. Warsaw surpassed Gdańsk as Poland''s most populous city by the 18th century. It served as the capital of the Polish–Lithuanian Commonwealth until 1795, and subsequently as the seat of Napoleon''s Duchy of Warsaw. The 19th century and its Industrial Revolution brought a demographic boom, which made it one of the largest and most densely populated cities in Europe. Known then for its elegant architecture and boulevards, Warsaw was bombed and besieged at the start of World War II in 1939. Much of the historic city was destroyed and its diverse population decimated by the Ghetto Uprising in 1943, the general Warsaw Uprising in 1944, and systematic razing.
Warsaw is served by three international airports, the busiest being Warsaw Chopin, as well as Warsaw Modlin and Warsaw Radom Airport. Major public transport services operating in the city include the Warsaw Metro, buses, commuter rail service and an extensive tram network. The city is a significant economic centre for the region, with the Warsaw Stock Exchange being the largest in Central and Eastern Europe. It is the base for Frontex, the European Union agency for external border security, and ODIHR, one of the principal institutions of the Organization for Security and Co-operation in Europe. Warsaw has one of Europe''s highest concentrations of skyscrapers, and the Varso Tower is the tallest building in the European Union.
The city''s primary educational and cultural institutions comprise the University of Warsaw, the Warsaw University of Technology, the SGH Warsaw School of Economics, the Chopin University of Music, the Polish Academy of Sciences, the National Philharmonic Orchestra, the National Museum, and the Warsaw Grand Theatre, which is among the largest in Europe. The reconstructed Old Town, which represents a variety of European architectural styles, was listed as a World Heritage Site by UNESCO in 1980. Other landmarks include the Royal Castle, Sigismund''s Column, the Wilanów Palace, the Palace on the Isle, St. John''s Archcathedral, Main Market Square, and numerous churches and mansions along the Royal Route. Warsaw is a green capital, with around a quarter of the city''s area occupied by parks. In sports, the city is home to Legia and Polonia sports clubs and hosts the annual Warsaw Marathon.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/35/Aleja_Niepdleglosci_Warsaw_2022_aerial_%28cropped%29.jpg/960px-Aleja_Niepdleglosci_Warsaw_2022_aerial_%28cropped%29.jpg', website_url = 'https://en.wikipedia.org/wiki/Warsaw' WHERE id = '7df81ed9-f8ea-4147-b9d9-dff9e3057bee';
UPDATE universities SET description = 'Işık University (Turkish: Işık Üniversitesi) is a private university located in Istanbul, Turkey. The university operates under the Feyziye Schools Foundation''s Işık Schools, which originated with the establishment of the Feyz-i Sıbyan School in the city of Salonica, modern Thessaloniki, on 14 December 1885.', cover_image_url = NULL, website_url = 'https://en.wikipedia.org/wiki/I%C5%9F%C4%B1k_University' WHERE id = '44202e75-4f7c-4564-b844-3b5ba529734f';
UPDATE universities SET description = 'The Queen''s University of Belfast, commonly known as Queen''s University Belfast (Irish: Ollscoil na Banríona; abbreviated Queen''s or QUB), is a public research university in Belfast, Northern Ireland, United Kingdom. The university received its charter in 1845 as part of the Queen''s University of Ireland and opened four years later, together with University of Galway (as Queen''s College, Galway) and University College Cork (as Queen''s College, Cork).
Queen''s offers approximately 300 academic degree programmes at various levels. The current president and vice-chancellor is Ian Greer. The annual income of the institution for 2024–25 was £493.8 million, of which £112.4 million was from research grants and contracts, with an expenditure of £511.5 million.
Queen''s is a member of the Russell Group of research-intensive universities, the Association of Commonwealth Universities, the European University Association, Universities UK and Universities Ireland. The university is associated with two Nobel laureates and one Turing Award laureate.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5a/Queen%27s_University_Belfast_arms.svg/960px-Queen%27s_University_Belfast_arms.svg.png', website_url = 'https://en.wikipedia.org/wiki/Queen%27s_University_Belfast' WHERE id = 'a67da25a-20ca-42f5-8d73-d9a98fd5c83d';
UPDATE universities SET description = 'Osman Aşkın Bak (born October 11, 1966) is a Turkish mechanical engineer, politician and the current Minister of Youth and Sports.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/b/bc/Osman_A%C5%9Fk%C4%B1n_Bak_20241107_%28cropped%29.jpg/960px-Osman_A%C5%9Fk%C4%B1n_Bak_20241107_%28cropped%29.jpg', website_url = 'https://en.wikipedia.org/wiki/Osman_A%C5%9Fk%C4%B1n_Bak' WHERE id = '880e410d-1753-4b77-bf56-c16269a08ca7';
UPDATE universities SET description = 'The Sebilj is an Ottoman-style wooden fountain (sebil) in the centre of Baščaršija Square in Sarajevo. The original Sebilj was built by Mehmed Pasha Kukavica in 1753, but it was destroyed in a fire in 1852. It was reconstructed by the Austrian architect Alexander Wittek in 1891, and was relocated to its present site several metres away from the position of the earlier structure. According to local legend, visitors who drink water from the fountain will return to Sarajevo someday.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/1/1d/Sebilj_%28by_day%29.jpg/960px-Sebilj_%28by_day%29.jpg', website_url = 'https://en.wikipedia.org/wiki/Sebilj_in_Sarajevo' WHERE id = 'da3e1f20-647d-454d-a78c-aeff95002ce9';
UPDATE universities SET description = 'The Epstein files are a partially released collection of millions of documents, images, videos, and emails detailing the activities of American financier and convicted child sex offender Jeffrey Epstein, including his social circle of public figures, politicians, and celebrities. The files include documents collected as evidence in the criminal cases against Epstein and his associates, stored as over 300 gigabytes of data, alongside other media, in the FBI''s Sentinel case management system. They include Epstein''s contacts book, flight logs of his planes, and court documents. Many of the records and files belong to Epstein''s estate, which is run by lawyer Darren Indyke and accountant Richard Kahn.
In November 2025, the U.S. House of Representatives passed the Epstein Files Transparency Act, and the U.S. Senate unanimously approved it, with President Donald Trump signing the bill into law the next day. The following month, the U.S. Department of Justice released a relatively small number of files, leading to criticism from both major parties in the US. Trump had previously floated the idea of releasing the files during his 2024 presidential campaign; he later said that controversies surrounding the files were fabricated by members of the Democratic Party.
In January 2026, an additional 3 million pages were released, including 2,000 videos and 180,000 images. While the Department of Justice acknowledged that a total of 6 million pages might qualify as files required to be released, it stated that the January 30 release would be the final one, and that it had met its legal obligations. The released files mentioned a number of public figures, and led to increased scrutiny of their activities. Individuals whose names have shown up frequently in the files include: Epstein''s assistant Lesley Groff, accountant Richard Kahn, Trump and his wife Melania Trump, lawyer Darren Indyke, sex trafficker and socialite Ghislaine Maxwell, and modeling agent Jean-Luc Brunel.
As of February 2026, three people have had criminal investigations launched into them due to their ties to Epstein, with one resulting in criminal charges and the others resulting in arrests thus far: former Norwegian prime minister Thorbjørn Jagland, who has been charged with aggravated corruption; Andrew Mountbatten-Windsor, and British politician Peter Mandelson.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/23/Epstein_Files_Phase_1%2C_Part_C_%E2%80%93_Contact_Book_Redacted.pdf/page1-960px-Epstein_Files_Phase_1%2C_Part_C_%E2%80%93_Contact_Book_Redacted.pdf.jpg', website_url = 'https://en.wikipedia.org/wiki/Epstein_files' WHERE id = '443d40aa-cfff-429d-b4bc-73c5163012a3';
UPDATE universities SET description = 'Bilkent University (Turkish: Bilkent Üniversitesi) is a private non-profit research university located in Ankara, Turkey. It was founded by İhsan Doğramacı, the  first president of the Council of Higher Education and the head of the prominent Doğramacı family,  with the aim of creating a center of excellence in higher education and research in 1984. It has constantly been ranked among the top Turkish universities since its establishment. In 2011, it was ranked 112th in the world by Times World University Rankings. Bilkent University was the first non-profit private university established in the country. The name Bilkent is an abbreviation of bilim kenti, meaning "city of science" in Turkish.', cover_image_url = NULL, website_url = 'https://en.wikipedia.org/wiki/Bilkent_University' WHERE id = '9ebc0b0a-f96f-443b-9a54-3b0d1c1a3c37';
UPDATE universities SET description = 'Özyeğin University is a private non-profit university located in Istanbul, Turkey.', cover_image_url = NULL, website_url = 'https://en.wikipedia.org/wiki/%C3%96zye%C4%9Fin_University' WHERE id = 'bfabff2c-5e31-4b5d-9871-552ccabcc405';
UPDATE universities SET description = 'İstanbul Kültür University (İKÜ) is one of the many private universities located in Istanbul, Turkey.  It has a total of four campuses all in close proximity to each other in the western part of Istanbul. The three campuses are located in Şirinevler, İncirli, Basın Ekspres and Ataköy
This non-profit University was founded in 1997; its Industrial Engineering started in the 1997–98 academic year. The university has five schools and two vocational schools. In 2009, Global Political Trends Center, a policy oriented research (think tank) institution, was founded under the auspices of the university.
Istanbul Kültür University conducts its academic and scientific activities with a total of 59 departments and programs, in eight faculties, namely Faculty of Science and Letters, Faculty of Education, Faculty of Arts and Design, Faculty of Law, Faculty of Economic and Administrative Sciences, Faculty of Architecture, Faculty of Engineering and Faculty of Health Sciences, and in two vocational schools, namely Vocational School and Vocational School of Justice. In addition, it provides postgraduate education at 54 Master''s and 11 Ph.D. programs within the body of the Institute', cover_image_url = NULL, website_url = 'https://en.wikipedia.org/wiki/Istanbul_K%C3%BClt%C3%BCr_University' WHERE id = 'a5533145-417d-41b7-99fb-363cca51b0ac';
UPDATE universities SET description = 'Yeditepe University (Turkish: Yeditepe Üniversitesi) is a private non-profit university situated in Istanbul, Turkey. Established by the Istanbul Education and Culture Foundation (Turkish: İstanbul Eğitim ve Kültür Vakfı, İSTEK Vakfı) in 1996, Yeditepe University now claims to be the largest of the 74 private non-profit universities in Turkey. Students pay fees that vary according to discipline and faculty.', cover_image_url = NULL, website_url = 'https://en.wikipedia.org/wiki/Yeditepe_University' WHERE id = '29ff113a-d51c-4b36-83b3-0ed26f9968e0';
UPDATE universities SET description = 'Istanbul Beykent University (Turkish: İstanbul Beykent Üniversitesi) is a private non-profit university in Istanbul, Turkey, offering instruction in English and Turkish, with approximately 30,000 students.
Beykent University participates in the Erasmus Programme and has agreements with several European universities for student exchange between Turkey and European institutions. The university is a member of the Caucasus University Association.

', cover_image_url = NULL, website_url = 'https://en.wikipedia.org/wiki/Istanbul_Beykent_University' WHERE id = 'af35d788-5322-44d0-90ac-b7b8a0d418ba';
UPDATE universities SET description = 'Atılım University (In Turkish: Atılım Üniversitesi) is a  private university established in 1996. It is located in Ankara, the capital of Turkey. The language of instruction for most courses is English. Education programs are at international standards (e.g. ABET 2000).', cover_image_url = NULL, website_url = 'https://en.wikipedia.org/wiki/At%C4%B1l%C4%B1m_University' WHERE id = '3fa17bd9-1cae-4323-8164-93997c29e1b7';
UPDATE universities SET description = 'Kyrenia is a city on the northern coast of Cyprus, noted for its historic harbour and castle. It is under the control of Northern Cyprus.
While there is evidence showing that the wider region of Kyrenia has been populated before, Greek myths suggest Kyrenia was founded by the Achaeans Cepheus and Praxandrus who ended up there after the Trojan War. The heroes named the new city after their hometown Kyrenia in Achaea, Greece.
As the town grew prosperous, the Romans established the foundations of its castle in the 1st century AD. Kyrenia grew in importance after the 9th century due to the safety offered by the castle, and played a pivotal role under Lusignan rule as the city never capitulated. The castle was most recently modified by the Venetians in the 15th century. The city surrendered to the Ottoman Empire in 1571.
The city''s population was almost equally divided between Muslims and Christians in 1831, with a slight Muslim majority. However, with the advent of British rule, many Turkish Cypriots fled to Anatolia, and the town came to be predominantly inhabited by Greek Cypriots. While the city suffered little intercommunal violence, its Greek Cypriot inhabitants, numbering around 2,650, fled or were forcefully displaced in the wake of the Turkish invasion in 1974. Currently, the city is populated by Turkish Cypriots, mainland Turkish settlers, and British expats, with a municipal population of 33,207.
Kyrenia is a cultural and economical centre, described as the tourism capital of Northern Cyprus. It is home to numerous hotels, nightlife and a port. It hosts an annual culture and arts festival with hundreds of participating artists and performers and is home to three universities with a student population around 14,000.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/c/c4/Kyrenia_01-2017_img04_view_from_castle_bastion.jpg/960px-Kyrenia_01-2017_img04_view_from_castle_bastion.jpg', website_url = 'https://en.wikipedia.org/wiki/Kyrenia' WHERE id = '77887cfd-8975-4638-920b-89502beac1ab';
UPDATE universities SET description = 'Kadir Has University (Turkish: Kadir Has Üniversitesi), often abbreviated as KHAS, is a private non-profit university in Fatih, Istanbul, established in 1997 by Kadir Has, the late Turkish industrialist and philanthropist.
Research centers at Kadir Has University include the Centre for Energy and Sustainable Development, Istanbul Studies Center, Sports Studies Research Center, Gender and Women’s Studies Centre, the Center for International and European Studies, and the Centre for Cybersecurity and Critical Infrastructure Protection. Additionally, Kadir Has University supports its students with financial aid and consultancy services through entities such as the Creative Industries Platform.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/b/bb/KadirHasUniversity.JPG/960px-KadirHasUniversity.JPG', website_url = 'https://en.wikipedia.org/wiki/Kadir_Has_University' WHERE id = '86e7d920-e5a1-4f50-82b2-cebda68eea19';
UPDATE universities SET description = 'Istanbul Nişantaşı University (Turkish: İstanbul Nişantaşı Üniversitesi) is a private, non-profit educational institution, founded in 2012 and located in Istanbul, Turkey. The university is supported financially by the Nişantaşı Education and Culture Foundation. It started education in the academic term 2010-11.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/d/d1/Mavi.png/960px-Mavi.png', website_url = 'https://en.wikipedia.org/wiki/Istanbul_Ni%C5%9Fanta%C5%9F%C4%B1_University' WHERE id = '77c4e6ee-49ee-4f62-bac7-87cb54979815';
UPDATE universities SET description = 'Başkent University (Turkish: Başkent Üniversitesi) is a private university in Ankara, Turkey. The university was founded on 13 January 1994 by Professor Dr. Mehmet Haberal. The university center is located in Ankara and also has medical and research centers and dialysis centers all around Turkey.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/87/Ba%C5%9Fkent_%C3%9Cniversitesi_logo.svg/960px-Ba%C5%9Fkent_%C3%9Cniversitesi_logo.svg.png', website_url = 'https://en.wikipedia.org/wiki/Ba%C5%9Fkent_University' WHERE id = 'b8f48d61-b429-482d-8cce-73a21ac17825';
UPDATE universities SET description = 'Istanbul Şehir University (Turkish: İstanbul Şehir Üniversitesi, lit. ''City University of Istanbul'') was a private, non-profit university located in Istanbul, Turkey. It was established in 2008 by the Bilim ve Sanat Vakfı (BiSaV or BSV, English: Foundation for Science and Arts). The university started its education in the academic year of 2010–11 at its campus in Altunizade, Üsküdar, following a ceremony held on October 5, 2010 that was attended by then President Abdullah Gül, Prime Minister Recep Tayyip Erdoğan and Minister of Foreign Affairs Ahmet Davutoğlu.
The university was closed down on June 30, 2020, after it faced financial difficulties stemming from a legal land dispute, which in turn was fueled by a bitter political feud. With Presidential Decree No. 2708, issued on June 30, 2020, the official authorization of Istanbul Şehir University was revoked. Following this decision, the university''s campus and students were transferred to Marmara University.', cover_image_url = NULL, website_url = 'https://en.wikipedia.org/wiki/Istanbul_%C5%9Eehir_University' WHERE id = '422e2473-3912-4efe-88c0-4af4d4df1f80';
UPDATE universities SET description = 'Istanbul Yeni Yüzyıl University (Turkish: İstanbul Yeni Yüzyıl Üniversitesi) was founded in 2009 in Turkey.', cover_image_url = NULL, website_url = 'https://en.wikipedia.org/wiki/Istanbul_Yeni_Y%C3%BCzy%C4%B1l_University' WHERE id = '552ff44f-7a3b-4f72-8bdb-cbfe4903372d';
UPDATE universities SET description = 'TED University is a private, non-profit university located in Ankara, Turkey. Established by the Turkish Education Association Higher Education Foundation on July 7, 2009, it began offering education in the 2012–2013 academic year with an initial cohort of 320 students. The university conducts its programs in English and is the second institution in Turkey to adopt a liberal arts-style education model, following Sabancı University. In 2021, it was one of three foundation universities in Turkey accredited by the Higher Education Quality Board, alongside Koç University and Bilkent University.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/45/TED_%C3%9Cniversitesi_01.jpg/960px-TED_%C3%9Cniversitesi_01.jpg', website_url = 'https://en.wikipedia.org/wiki/TED_University' WHERE id = '77cdd87e-38ae-47b9-acef-4314fc5834c9';
UPDATE universities SET description = 'Istanbul Sabahattin Zaim University (Turkish: İstanbul Sabahattin Zaim Üniversitesi) is a Turkish private higher-education institution established by "İlim Yayma Vakfı" (literally: Foundation for the Propagation of Science) on April 24, 2010. Classes at the university began in the 2011–12 term.
The university was named after Sabahattin Zaim (1926-2007), a professor of economics in the Faculty of Economics at Istanbul University until 1993. A Macedonian from birth, he served as the founding rector of the International University of Sarajevo in 2003-04 after he taught at several universities in and outside Turkey. He was also a founding member of İlim Yayma Vakfı.
The university''s main campus is located in Halkalı, the faculty building is situated in Altunizade, and the research center is in Eyüp.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/a/a6/%C4%B0stanbul_Sabahattin_Zaim_%C3%9Cniversitesi_-_Ey%C3%BCp_Yerle%C5%9Fkesi_-_Mart_2013.JPG/960px-%C4%B0stanbul_Sabahattin_Zaim_%C3%9Cniversitesi_-_Ey%C3%BCp_Yerle%C5%9Fkesi_-_Mart_2013.JPG', website_url = 'https://en.wikipedia.org/wiki/Istanbul_Sabahattin_Zaim_University' WHERE id = '122da343-ad1f-4e3c-8470-32bde26bec55';
UPDATE universities SET description = 'The Bloudy Tenent of Persecution, for Cause of Conscience, Discussed in a Conference between Truth and Peace is a 1644 book about government force written by Roger Williams, the co-founder of the English Colony of Rhode Island and Providence Plantations and the co-founder of the First Baptist Church in America. Tenent is an obsolete variant of tenet, and the book argues for a "wall of separation" between church and state and for state toleration of various Christian denominations, including Catholicism, and also "paganish, Jewish, Turkish or anti-Christian consciences and worships." The book takes the form of a dialogue between Truth and Peace and is a response to correspondence by Boston minister John Cotton regarding Cotton''s support for state enforcement of religious uniformity in the Massachusetts Bay Colony. Williams argues that Christianity requires the existence of a separate civil authority which may not generally infringe upon liberty of conscience, which Williams interpreted to be a God-given right.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/0/0b/The_Bloudy_Tenent_of_Persecution_for_Cause_of_Conscience_by_Roger_Williams.jpg/500px-The_Bloudy_Tenent_of_Persecution_for_Cause_of_Conscience_by_Roger_Williams.jpg', website_url = 'https://en.wikipedia.org/wiki/The_Bloudy_Tenent_of_Persecution_for_Cause_of_Conscience' WHERE id = '6eb2ef83-331f-43e3-9a90-10cf883e341e';
