UPDATE universities SET description = 'The Saint Louis Art Museum (SLAM) is an art museum located in St. Louis, Missouri, United States. With paintings, sculptures, cultural objects, and ancient masterpieces from around the world, its three-story building stands in Forest Park in St. Louis, Missouri, where it is visited by up to a half million people every year. Admission is free through a subsidy from the cultural tax district for St. Louis City and County.
In addition to the featured exhibitions, the museum offers rotating exhibitions and installations. These include the Currents series, which features contemporary artists, as well as regular exhibitions of new media art and works on paper.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5c/StLouisArtMuseum.jpg/960px-StLouisArtMuseum.jpg', website_url = 'https://en.wikipedia.org/wiki/Saint_Louis_Art_Museum' WHERE id = 'f07e3c03-eff7-4f8a-a3f4-55faf3c0fa01';
