UPDATE universities SET description = 'Leeds City Museum, established in 1819, is a museum in Leeds, West Yorkshire, England.  Since 2008 it has been housed in the former Mechanics'' Institute built by Cuthbert Brodrick, in Cookridge Street (now Millennium Square). It is one of eight sites in the Leeds Museums & Galleries group.
Special exhibitions are hosted alongside a collection of displays from the Leeds Archive.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/6b/Leeds-city-museum.jpg/960px-Leeds-city-museum.jpg', website_url = 'https://en.wikipedia.org/wiki/Leeds_City_Museum' WHERE id = 'd1c7c6e0-a7c6-4b5b-a331-b518eaa66277';
UPDATE universities SET description = 'The Labour and Socialist International (LSI) was an international organization of socialist and labourist parties, active between 1923 and 1940. The group was established through a merger of the rival Vienna International and the Berne International, and was the forerunner of the present-day Socialist International.
The LSI had a history of rivalry with the Communist International (Comintern), with which it competed over the leadership of the international socialist and labour movement. However, unlike the Comintern, the LSI maintained no direct control over the actions of its sections, being constituted as a federation of autonomous national parties.', cover_image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/e/e1/Labour_and_Socialist_International_logo.png/960px-Labour_and_Socialist_International_logo.png', website_url = 'https://en.wikipedia.org/wiki/Labour_and_Socialist_International' WHERE id = '3571e736-c975-455d-988a-e772036c35d0';
UPDATE universities SET description = 'LGBTQ migration refers to the movement of lesbian, gay, bisexual, transgender, and queer (LGBTQ) individuals across international borders or within a single country. Many migrate to escape discrimination, legal restrictions, violence, and social stigma—such as homophobia and transphobia—related to their sexuality or gender identity. Others seek greater social acceptance, legal protections, or economic opportunities. LGBTQ migrants often face social exclusion, violent retaliations, and socio-economic challenges in their home countries. Globally and domestically, many LGBTQ individuals attempt to leave discriminatory regions in search of more inclusive environments.', cover_image_url = NULL, website_url = 'https://en.wikipedia.org/wiki/LGBTQ_migration' WHERE id = '8d56c72a-3352-416b-aca8-a384cf085a39';
